class Solution {
    public String smallestNumber(String pattern) {
        char[] num = new char[pattern.length() + 1];
        int idx = 0;
        for (int i = 9; i >= 1; i--) {
            num[idx++] = (char) (i + '0');
            while (idx > 1 && pattern[idx - 2] == 'D') {
                idx--;
            }
        }
        return new String(num);
    }
}
